public class Solution {
    public static final long MOD = 1000000007;

    public static long modInverse(long a) {
        return BigInteger.valueOf(a).modInverse(BigInteger.valueOf(MOD)).longValue();
    }

    public static long solve(long[] nums, long[][] queries) {
        int n = nums.length;
        int B = (int) Math.sqrt(n) + 1;
        long[] totalFactor = new long[n];
        Arrays.fill(totalFactor, 1);

        List<Long[]>[][] smallGroups = new ArrayList[B][];
        for (int k = 1; k < B; k++) {
            smallGroups[k] = new ArrayList[k];
            for (int r = 0; r < k; r++) {
                smallGroups[k][r] = new ArrayList<>();
            }
        }

        for (long[] q : queries) {
            long l = q[0], r = q[1], ki = q[2], vi = q[3];
            if (ki >= B) {
                for (long idx = l; idx <= r; idx += ki) {
                    int i = (int) idx;
                    totalFactor[i] = (totalFactor[i] * vi) % MOD;
                }
            } else {
                int k = (int) ki;
                int r0 = (int) (l % ki);
                smallGroups[k][r0].add(new Long[]{l, r, vi});
            }
        }

        for (int k = 1; k < B; k++) {
            for (int r0 = 0; r0 < k; r0++) {
                if (smallGroups[k][r0].isEmpty()) continue;

                List<Long[]> queriesInGroup = smallGroups[k][r0];
                List<Long>[] events = new ArrayList[n + 1];
                for (int i = 0; i <= n; i++) events[i] = new ArrayList<>();

                for (Long[] q : queriesInGroup) {
                    long l = q[0], r = q[1], vi = q[2];
                    int lInt = (int) l;
                    int rPlus1 = (int) (r + 1);
                    events[lInt].add(vi);
                    if (rPlus1 < n) events[rPlus1].add(modInverse(vi));
                    else if (rPlus1 == n) events[n].add(modInverse(vi));
                }

                long current = 1;
                for (int i = 0; i < n; i++) {
                    for (long factor : events[i]) {
                        current = (current * factor) % MOD;
                    }
                    if (i % k == r0) {
                        totalFactor[i] = (totalFactor[i] * current) % MOD;
                    }
                }
            }
        }

        long result = 0;
        for (int i = 0; i < n; i++) {
            nums[i] = (nums[i] % MOD * totalFactor[i]) % MOD;
            result ^= nums[i];
        }
        return result;
    }
}
